/**
 * GENERATED COMPONENT — TimerList
 * Domain: Live Events (Stagetimer)
 * Primitive: useComposableList
 * Generated by: AI from hook + domain context
 *
 * Same useComposableList hook as ContactList — different domain, different rendering.
 */

import { useComposableList } from '../../hooks/composable'

interface TimerEntry {
  id: string
  label: string
  duration: number
  status: 'waiting' | 'running' | 'done'
}

function formatDuration(seconds: number): string {
  const m = Math.floor(seconds / 60)
  const s = seconds % 60
  return `${m}:${String(s).padStart(2, '0')}`
}

const STATUS_ICONS: Record<TimerEntry['status'], string> = {
  waiting: '⏳',
  running: '▶️',
  done: '✅',
}

interface TimerListProps {
  componentId: string
  listenToComponent?: string
  items?: TimerEntry[]
}

export function TimerList({ componentId, listenToComponent, items: initialItems }: TimerListProps) {
  const {
    items,
    selectedIndex,
    emitSelection,
  } = useComposableList<TimerEntry>({
    componentId,
    listenToComponent,
    initialItems: initialItems ?? [
      { id: '1', label: 'Opening Remarks', duration: 300, status: 'done' },
      { id: '2', label: 'Keynote Speaker', duration: 1800, status: 'running' },
      { id: '3', label: 'Panel Discussion', duration: 2700, status: 'waiting' },
      { id: '4', label: 'Q&A Session', duration: 900, status: 'waiting' },
      { id: '5', label: 'Closing', duration: 180, status: 'waiting' },
    ],
  })

  return (
    <div className="flex flex-col gap-1 bg-zinc-900 rounded-xl p-3">
      <div className="text-xs font-medium text-zinc-500 uppercase tracking-widest px-2 py-1">
        Schedule ({items.length} items)
      </div>
      {items.map((timer, index) => (
        <button
          key={timer.id}
          onClick={() => emitSelection(timer, index)}
          className={`w-full text-left px-3 py-2.5 rounded-lg transition-colors ${
            selectedIndex === index
              ? 'bg-green-500 bg-opacity-20 border border-green-500'
              : timer.status === 'running'
                ? 'bg-zinc-800 border border-zinc-700'
                : 'hover:bg-zinc-800'
          }`}
        >
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-sm">{STATUS_ICONS[timer.status]}</span>
              <span className={`text-sm ${
                timer.status === 'done' ? 'text-zinc-500 line-through' :
                timer.status === 'running' ? 'text-green-400 font-medium' :
                'text-zinc-300'
              }`}>
                {timer.label}
              </span>
            </div>
            <span className="text-xs text-zinc-500 font-mono">
              {formatDuration(timer.duration)}
            </span>
          </div>
        </button>
      ))}
    </div>
  )
}
